```class Solution {
public:
    int numberOfSpecialChars(string word) {
        unordered_map<char, int> lower, upper;
        int res = 0;
        for (int i = 0; i < word.size(); ++i) {
            if (islower(word[i])) lower[word[i]] = i;
            else upper[tolower(word[i])] = i;
        }
        for (auto& p : lower) {
            if (upper.count(p.first)) res += p.second < upper[p.first];
        }
        return res;
    }
};
